VALUES
  ('disabled-8b44517b-moex-00054', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '關於法規命令之效力，下列敘述何者錯誤？', '["法規命令牴觸上級機關之命令，無效", "法規命令無法律授權而限制人民自由權利，無效", "法規命令之一部分無效者，其他部分原則上仍為有效", "主管機關訂定之法規命令，依法應經其他機關核准，如未經核准者，原 則上仍為有效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00055', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '依行政程序法規定，有關法規命令之訂定程序，下列敘述何者正確？', '["人民或團體亦得提議訂定法規命令，但須同時提出具體之草案，以達到 人民推動行政立法之目的", "人民提議訂定之法規命令，若非屬於行政機關之職權，則無需進一步處置", "行政機關擬訂法規命令時，應於機關網站事先公告周知", "法規命令之訂定，行政機關得依職權舉行聽證"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00056', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '關於行政處分之分類，下列敘述何者錯誤？', '["下命處分係課予相對人作為、不作為或容忍義務之處分", "形成處分係設定、變更或消滅具體法律關係、權利、資格或法律地位之 處分", "暫時性行政處分係附有期限之行政處分", "確認處分包括對法律關係存否之確認"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00057', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '依行政程序法規定，有關禁止公務員與當事人程序外接觸之敘述，下列何 者錯誤？', '["公務員因職務上必要而為程序外接觸，並非法律所禁止之行為", "公務員與當事人為程序外接觸時所使用之書面文件，應對社會大眾公開", "如與當事人以電話聯絡，須作成書面紀錄，且將接觸對象、時間、地點 及內容清楚記載", "其他當事人如對公務員程序外接觸有疑義，不得立即提出救濟，僅得對 實體決定聲明不服時一併提出"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00058', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '依行政程序法規定，關於行政行為一部無效之敘述，下列何者錯誤？', '["行政處分一部分無效者，其他部分原則仍為有效", "行政指導之一部無效者，原則全部無效", "行政契約之一部無效者，原則全部無效", "法規命令之一部分無效者，其他部分原則仍為有效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00059', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '關於行政契約之履行，下列敘述何者錯誤？', '["人民與締約機關簽訂行政契約，認為締約機關所屬公法人之其他機關於 契約關係外行使公權力，造成其受有不可預期之損失，應在知有損失時 起1年內，向締約機關請求補償損失", "行政契約約定自願接受執行時，債務人不為給付時，債權人得以該契約 為強制執行之執行名義", "基於契約自由原則，簽訂行政契約之行政機關，不得以任何理由，主張 調整該行政契約", "行政機關與人民訂定行政契約，行政機關得依書面約定之方式，就相對 人契約之履行，為必要之行政指導"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00060', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '依實務見解，下列何者非行政事實行為？', '["主管機關於交叉路口視線不良處設置反射鏡", "主管機關拒絕人民行政程序重開之申請", "主管機關對垃圾清運路線之變更", "主管機關拒絕建商申請註銷其依職權就鄰損事件所為之列管"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00061', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '有關行政訴訟之確認訴訟，下列敘述何者錯誤？', '["人民可提起確認行政處分有效之行政訴訟", "原告提起確認行政處分無效，須有即受確認判決之法律上利益", "原告提起確認行政處分無效之訴訟，須先向原處分機關請求確認其無效 未被允許，或經請求後於30日內不為確答，始可提起", "如原告依法可提起撤銷訴訟，即不得提起確認公法上法律關係不成立之 訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00062', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '下列何者並非行政執行法所規定法務部行政執行署所屬分署向法院聲請 管收之要件？', '["義務人顯有履行義務之可能，故不履行", "義務人欠稅達新臺幣100萬元以上", "義務人顯有逃匿之虞", "義務人就應供強制執行之財產有隱匿之情事"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00063', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '甲依政府資訊公開法規定，向A區公所申請其持有之區工作會報及里長會 議資料，下列敘述何者正確？', '["此資訊屬於合議制機關之會議紀錄，A區公所應主動公開", "A區公所原則上應於受理申請之日起15日內，為准駁之決定", "若 A 區公所拒絕甲之申請，甲對 A 區公所之決定不服，應提起撤銷訴 願及撤銷訴訟以資救濟", "若甲所申請之資訊內容，部分含有依政府資訊公開法第18條第1項規定， 應不予提供之資訊時，A區公所即得拒絕提供甲所申請之全部資訊內容"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL)
